INSERT INTO t_amz_settlement_report
 SELECT * FROM  t_amz_settlement_report_archive
WHERE settlement_id =#{settlementId,jdbcType=CHAR}

INSERT INTO t_amz_settlement_report_archive
 SELECT * FROM  t_amz_settlement_report
WHERE settlement_id =#{settlementId,jdbcType=CHAR}

mapper.select:
select  d.posted_date,sum(d.amount) 
from  
   t_amz_settlement_summary_day d
   left join t_amazon_auth a on a.id=d.amazonAuthId
where 
 d.posted_date>=#{begindate,jdbcType=DATE}
and d.posted_date<=#{enddate,jdbcType=DATE}

    and d.marketplace_name=#{marketplace_name,jdbcType=CHAR}


	and a.groupid=#{groupid,jdbcType=CHAR}

and a.shop_id=#{shopid,jdbcType=CHAR}
and d.amount_description='Principal'
group by d.posted_date

    select g.name groupname, r.*
		from  
		   t_amz_settlement_report   r
		   left join t_amz_settlement_acc_report rt on rt.settlement_id=r.settlement_id
		   left join t_amazon_auth a on a.id=r.amazonAuthId
		   left join t_amazon_group g on g.id=a.groupid
		where
		   a.shop_id=#{shopid,jdbcType=CHAR}

		   and r.amazonAuthId=#{amazonauthid,jdbcType=CHAR} 


			and a.groupid=#{groupid,jdbcType=CHAR} 


			and rt.marketplace_name=#{marketplace_name,jdbcType=CHAR} 


			 and r.settlement_id=#{settlementId,jdbcType=CHAR} 


			 and r.sku=#{sku,jdbcType=CHAR} 



			        and r.posted_date>=#{fromDate,jdbcType=CHAR}
	  	            and r.posted_date<=#{endDate,jdbcType=CHAR}




	  	         and rt.deposit_date>=#{fromDate,jdbcType=CHAR}
	  	         and rt.deposit_date<=#{endDate,jdbcType=CHAR}


	  	         and r.posted_date>=#{setfromDate,jdbcType=CHAR}
	  	         and r.posted_date<=#{setendDate,jdbcType=CHAR}


	  	          and rt.amazonauthid=#{amazonauthid,jdbcType=CHAR} 


	  	          and rt.marketplace_name=#{marketplace_name,jdbcType=CHAR}

select transaction_type,amount_type,amount_description,sum(r.amount) amount,max(r.currency) currency from t_amz_settlement_summary_month r left join t_amz_settlement_acc_report rt on rt.settlement_id=r.settlementid where r.settlementid=#{settlement_id,jdbcType=CHAR}
and r.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}
group by transaction_type,amount_type,amount_description

      select transaction_type,amount_type,amount_description,DATE_FORMAT(r.posted_date,'%m-%d') posted_date,
      sum(r.amount) amount,max(r.currency) currency
		from  
		   t_amz_settlement_report   r
		   left join t_amz_settlement_acc_report rt on rt.settlement_id=r.settlement_id
		where  1=1

		   and  r.posted_date>=#{fromDate,jdbcType=CHAR}
  	       and r.posted_date<=#{endDate,jdbcType=CHAR}


			and r.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}


			and  rt.marketplace_name=#{market,jdbcType=CHAR} 


			 and ifnull(r.sku,'*')=#{sku,jdbcType=CHAR}


			 and r.settlement_id=#{settlement_id,jdbcType=CHAR}

  	     group by transaction_type,amount_type,amount_description,r.posted_date

      select transaction_type,amount_type,amount_description,DATE_FORMAT(r.posted_date,'%m-%d') posted_date,
      sum(r.amount) amount,max(r.currency) currency
		from  
		   t_amz_settlement_summary_day   r

		    left join t_amz_settlement_acc_report acc on acc.settlement_id=r.settlementid

				where  1=1 

			        and r.posted_date>=#{fromDate,jdbcType=CHAR}
	  	            and r.posted_date<=#{endDate,jdbcType=CHAR}


	  	         and acc.deposit_date>=#{fromDate,jdbcType=CHAR}
	  	         and acc.deposit_date<=#{endDate,jdbcType=CHAR}
	  	         and r.posted_date>=#{setfromDate,jdbcType=CHAR}
	  	         and r.posted_date<=#{setendDate,jdbcType=CHAR}

	  	          and acc.amazonauthid=#{amazonauthid,jdbcType=CHAR} 


	  	          and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR} 



			and r.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}


			and  r.marketplace_name=#{market,jdbcType=CHAR} 


			 and r.sku=#{sku,jdbcType=CHAR}

  	     group by transaction_type,amount_type,amount_description,r.posted_date

      select transaction_type,amount_type,amount_description
		from  distinct t_amz_settlement_summary_day   r
		where r.posted_date>=#{fromDate,jdbcType=CHAR}
  	       and r.posted_date<=#{endDate,jdbcType=CHAR}

			and r.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}


			and  r.marketplace_name=#{marketplace_name,jdbcType=CHAR} 

          and r.sku='*'

       select *from (
       select transaction_type,amount_type,amount_description,DATE_FORMAT(r.posted_date,'%m-%d') posted_date,
         sum(r.amount) amount,max(r.currency) currency
		from  
		   t_amz_settlement_summary_day r

		    left join t_amz_settlement_acc_report acc on acc.settlement_id=r.settlementid

		      where 1=1

		   and r.posted_date>=#{fromDate,jdbcType=CHAR}
  	       and r.posted_date<=#{endDate,jdbcType=CHAR}


  	         and acc.deposit_date>=#{fromDate,jdbcType=CHAR}
  	         and acc.deposit_date<=#{endDate,jdbcType=CHAR}
  	         and r.posted_date>=#{setfromDate,jdbcType=CHAR}
  	         and r.posted_date<=#{setendDate,jdbcType=CHAR}

  	          and acc.amazonauthid=#{amazonauthid,jdbcType=CHAR} 


  	          and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR} 



			and r.amazonAuthId=#{amazonAuthId,jdbcType=CHAR}


			and  r.marketplace_name=#{market,jdbcType=CHAR} 


			 and ifnull(r.sku,'*')=#{sku,jdbcType=CHAR}

  	     group by transaction_type,amount_type,amount_description,r.posted_date) v
         where 
                not(amount_description='Principal' and transaction_type='Order' ) 
				and not(amount_description like 'Commission%' and  (transaction_type='Order' or  transaction_type='Refund') ) 
				and not(amount_description like 'FBA%' and transaction_type='Order') 
				and not(amount_description='Principal' and transaction_type='Refund') 
			    AND ((currency!='EUR' and currency!='GBP') or not(amount_description='Tax' and transaction_type='Order' and amount_type='ItemPrice'))

      select transaction_type,amount_type,amount_description,DATE_FORMAT(r.posted_date,'%m-%d') posted_date,
      sum(r.amount) amount,max(r.currency) currency
		from  
		   t_amz_settlement_summary_month   r
		   left join t_amazon_auth a on a.id=r.amazonauthid

			 left join t_amz_settlement_acc_report acc on acc.settlement_id=r.settlementid

		where 1=1

		        and r.posted_date>=#{fromDate,jdbcType=CHAR}
  	            and r.posted_date<=#{endDate,jdbcType=CHAR}


  	         and acc.deposit_date>=#{fromDate,jdbcType=CHAR}
  	         and acc.deposit_date<=#{endDate,jdbcType=CHAR}
  	         and r.posted_date>=#{setfromDate,jdbcType=CHAR}
  	         and r.posted_date<=#{setendDate,jdbcType=CHAR}

  	          and acc.amazonauthid=#{amazonauthid,jdbcType=CHAR} 


  	          and acc.marketplace_name=#{marketplace_name,jdbcType=CHAR} 



  	       and
  	       	 (
             		r.amazonAuthId=#{auth.id,jdbcType=CHAR} 
          	 )


			and a.groupid=#{groupid,jdbcType=CHAR}


			and  r.marketplace_name=#{market,jdbcType=CHAR} 

  	     group by transaction_type,amount_type,amount_description,r.posted_date

	select sum(d.amount) 
	from  
	   t_amz_settlement_summary_day d
	   left join t_amazon_auth a on a.id=d.amazonAuthId
	where
	 d.posted_date>=#{begindate,jdbcType=DATE}
	and d.posted_date<=#{enddate,jdbcType=DATE}
	and d.amount_description='Principal' 
    and a.shop_id=#{shopid,jdbcType=CHAR}

	    and d.marketplace_name=#{marketplace_name,jdbcType=CHAR}


		and a.groupid=#{groupid,jdbcType=CHAR}

select   sum(refundnum) refundnum,  sum(order_amount) order_amount, sum(sales) sales
from  
    t_amz_settlement_summary_sku
where 
    posted_date>=#{begindate,jdbcType=DATE}
    and posted_date<=#{enddate,jdbcType=DATE}

    and d.marketplace_name=#{marketplace_name,jdbcType=CHAR}


	and a.groupid=#{groupid,jdbcType=CHAR}

    and a.shop_id=#{shopid,jdbcType=CHAR}

select v2.currency, v2.groupname, v2.marketname, v2.asin, v2.sku, v2.pname, v2.mname, v2.image, v2.categoryname, v2.ownername, v2.sales, v2.price, v2.`refundorder` refundsales, v2.order_amount, v2.storageFee skuStorageFee, v2.rpt_adv_spend_fee, v2.fin_sum_fee, v2.local_unit_price, ifnull(v.principalWithoutTax,0) +ifnull(v.refund,0) +ifnull(v.fbafee,0) +ifnull(v.digital,0) +ifnull(v.commission,0) +ifnull(v.reimbursement,0) -ifnull(v2.storageFee,0) -ifnull(v2.rpt_adv_spend_fee,0) -ifnull(v2.fin_sum_fee,0) -ifnull(v2.price,0) profit, ( ifnull(v.principalWithoutTax,0) +ifnull(v.refund,0) +ifnull(v.fbafee,0) +ifnull(v.digital,0) +ifnull(v.commission,0) +ifnull(v.reimbursement,0) -ifnull(v2.storageFee,0) -ifnull(v2.rpt_adv_spend_fee,0) -ifnull(v2.fin_sum_fee,0) -ifnull(v2.price,0))/v.principalWithoutTax profitRate, v.* from ( select m.amazonAuthId, m.marketplace_name, m.sku, max(m.currency) currency, max(g.name) groupname, max(mk.name) marketname, max(i.name) pname, max(i.asin) asin, max(mt.name) mname, max(ifnull(p.location,p.url)) image, max(c.name) categoryname, max(u.name) ownername, sum(sales) sales, sum(order_amount) order_amount, sum(m.`local_unit_price`*m.sales) price, max(m.`local_unit_price`) `local_unit_price`, sum(m.`refundorder`) `refundorder`, sum(case when m.sku like 'amzn.gr.%' then 0 else ifnull(m.rpt_storage_fee,0)+ifnull(m.rpt_long_storage_fee,0) end) storageFee, sum(m.rpt_adv_spend_fee) rpt_adv_spend_fee, sum(m.fin_sum_fee) fin_sum_fee from t_amz_settlement_summary_sku_month m left join t_product_info i on i.id=m.pid left join t_marketplace mk on mk.point_name=m.marketplace_name left join t_erp_material mt on mt.id=m.mid left join t_erp_material_category c on c.id=m.categoryid left join t_picture p on p.id=i.image left join t_amazon_auth a on a.id=m.amazonAuthId left join t_amazon_group g on g.id=a.groupid left join t_userinfo u on u.id=m.owner WHERE a.shop_id=#{params.shopid,jdbcType=CHAR}
AND mk.marketplaceid = #{params.marketplaceid,jdbcType=CHAR}
AND a.groupid = #{params.groupid,jdbcType=CHAR}
AND m.amazonAuthId = #{params.amazonauthid,jdbcType=CHAR}
AND m.sku like #{params.search,jdbcType=CHAR}
AND m.posted_date >=#{params.fromDate,jdbcType=CHAR} AND m.posted_date < #{params.endDate,jdbcType=CHAR} GROUP BY m.amazonAuthId,m.marketplace_name,m.sku) v2 left join (SELECT m.sku vsku,m.amazonAuthId,m.marketplace_name, sum(case when (amount_description='Principal' and amount_type='ItemPrice' and transaction_type='Order') or (amount_description='Tax' and transaction_type='Order' and amount_type='ItemPrice' ) then amount else 0 end ) principal, sum(case when amount_description='Principal' and amount_type='ItemPrice' and transaction_type='Order' then amount else 0 end ) principalWithoutTax, sum(case when transaction_type='Refund' then amount else 0 end ) refund, sum(case when amount_description like 'Commission' and transaction_type='Order' then amount else 0 end ) commission, sum(case when (amount_description like 'FBAPerUnitFulfillmentFee%' or amount_type like 'FBA fulfilment fee per unit%' ) and (transaction_type='Order' or transaction_type='AmazonFees') then amount else 0 end ) fbafee, SUM(case when 'FBA Inventory Reimbursement'=amount_type AND m.transaction_type='other-transaction' then amount ELSE 0 END ) reimbursement, sum(case when (amount_description='MarketplaceFacilitatorVAT-Principal' OR amount_description='MarketplaceFacilitatorVAT-Shipping') AND amount_type='ItemWithheldTax' then amount else 0 end) vat, SUM(case when ((m.amount_description in ('DisposalComplete', 'FBAInboundTransportationFee', 'FBAInboundTransportationProgramFee', 'Storage Fee', 'StorageRenewalBilling') AND m.transaction_type ='other-transaction') OR (m.amount_type in ('FBA Inventory Storage Fee','FBA Long Term Storage Fee') and m.transaction_type='FBAFees')) then amount else 0 end ) storagefee, SUM( case when (amount_type='Promotion' OR amount_type='PromotionFee' ) then amount ELSE 0 END ) promotion, sum(case when ((amount_description='Shipping' and amount_type='ItemPrice' ) or (amount_description='ShippingChargeback' and amount_type='ItemFees' ) or (amount_description='ShippingTax' and amount_type='ItemPrice' ) ) then amount else 0 end ) shipping, SUM(case when transaction_type='Liquidations' then amount ELSE 0 END ) liquidations, sum(case when amount_type='CouponRedemptionFee' then amount else 0 END ) coupon, SUM( case when amount_description LIKE 'FBA International Freight Shipping%' then amount else 0 END) freight, SUM( case when ( (amount_description='DigitalServicesFee' OR amount_description='Digital Services Fee') AND amount_type='ItemFees' ) then amount ELSE 0 END ) digital, sum(case when not(amount_description='Principal'and amount_type='ItemPrice'and transaction_type='Order') and not (amount_description='Tax' and transaction_type='Order' and amount_type='ItemPrice') and not ( transaction_type='Refund' AND amount_type='ItemPrice' AND amount_description='Principal' OR (amount_description='Tax' and transaction_type='Refund' and amount_type='ItemPrice') ) and not ( (amount_description like 'Commission%' OR amount_description='RefundCommission') and amount_type='ItemFees' ) and not ((amount_description like 'FBAPerUnitFulfillmentFee%' or amount_type like 'FBA fulfilment fee per unit%' ) and (transaction_type='Order' or transaction_type='AmazonFees')) AND NOT ( 'FBA Inventory Reimbursement'=amount_type OR 'Manual Processing Fee Reimbursement'=amount_type OR 'Item Fee Adjustment'=amount_type ) and not (amount_type='CouponRedemptionFee' ) AND NOT (amount_description='DigitalServicesFee' AND amount_type='ItemFees' ) AND NOT ( amount_description LIKE 'FBA International Freight Shipping%' ) and not ((amount_description='Shipping' and amount_type='ItemPrice' ) or (amount_description='ShippingChargeback' and amount_type='ItemFees' ) or (amount_description='ShippingTax' and amount_type='ItemPrice' ) ) and not (amount_type='Promotion' OR amount_type='PromotionFee') AND NOT ( (amount_description='DigitalServicesFee' OR amount_description='Digital Services Fee') AND amount_type='ItemFees' ) AND NOT (transaction_type='Liquidations') and NOT ((amount_description='MarketplaceFacilitatorVAT-Principal' OR amount_description='MarketplaceFacilitatorVAT-Shipping') AND amount_type='ItemWithheldTax' ) and not ((m.amount_description in ('DisposalComplete', 'FBAInboundTransportationFee', 'FBAInboundTransportationProgramFee', 'Storage Fee', 'StorageRenewalBilling') AND m.transaction_type ='other-transaction') OR (m.amount_type in ('FBA Inventory Storage Fee','FBA Long Term Storage Fee') and m.transaction_type='FBAFees')) then amount else 0 end) other, sum(amount) shopfee FROM t_amz_settlement_summary_day m LEFT JOIN t_marketplace mk ON mk.point_name=m.marketplace_name LEFT JOIN t_amazon_auth a on a.id=m.amazonAuthId WHERE a.shop_id=#{params.shopid,jdbcType=CHAR}
AND mk.marketplaceid = #{params.marketplaceid,jdbcType=CHAR}
AND a.groupid = #{params.groupid,jdbcType=CHAR}
AND m.amazonAuthId = #{params.amazonauthid,jdbcType=CHAR}
AND m.posted_date >=#{params.fromDate,jdbcType=CHAR} AND m.posted_date < #{params.endDate,jdbcType=CHAR} GROUP BY m.amazonAuthId,m.marketplace_name,m.sku) v on v2.amazonAuthId=v.amazonAuthId and v2.sku=v.vsku and v2.marketplace_name=v.marketplace_name
